    if (this.x + this.w > level.worldWidth){ this.x = level.worldWidth - this.w; this.vx = 0; }
    if (this.y + this.h > level.worldHeight){
      this.y = level.worldHeight - this.h;
      this.vy = 0; this.onGround = true;
    }
