    var bob = Math.sin(t*6 + this.pulse) * 2;
    ctx.fillStyle = G.colors.coin;
    ctx.beginPath();
    ctx.arc(Math.floor(this.x - camX), Math.floor(this.y + bob), this.r, 0, Math.PI*2);
