    // Platforms and ground
    for (var i=0;i<this.platforms.length;i++){
      var p = this.platforms[i];
      var sx = Math.floor(p.x - camX);
      if (sx + p.w < -5 || sx > G.WIDTH + 5) continue;
      ctx.fillStyle = (p.h > 50 ? G.colors.ground : G.colors.platform);
