# Optional syntax check with Node.js if available
node_ok = True
node_msgs = []
def node_check(js_path):
    try:
        r = subprocess.run(["node", "--check", js_path], capture_output=True, text=True)
        return r.returncode == 0, (r.stdout.strip() + "\n" + r.stderr.strip()).strip()
    except FileNotFoundError:
        return None, "node not found"

for fname in ["core.js","input.js","player.js","coin.js","enemy.js","level.js","game.js"]:
    ok, msg = node_check(f"{base}/{fname}")
    if ok is None:
