}

for path, content in files.items():
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)

# Verification

def must(cond, msg):
    if not cond:
        raise AssertionError(msg)

# Basic existence and non-empty
for path in files:
    must(os.path.exists(path), f"Missing file: {path}")
    must(os.path.getsize(path) > 0, f"Empty file: {path}")

# index.html checks
with open(f"{base}/index.html", "r", encoding="utf-8") as f:
    idx = f.read()
must(re.search(r'<canvas[^>]*id=["\\\']game["\\\']', idx, re.I) is not None, "index.html missing canvas#game")
for src in ["core.js","input.js","player.js","coin.js","enemy.js","level.js","game.js"]:
    must(src in idx, f"index.html missing script for {src}")

# JS signature checks
sig_checks = {
    "core.js": ["window.Game", "GRAVITY", "rectsIntersect", "drawSky"],
    "input.js": ["Game.Input", "isDown"],
    "player.js": ["Game.Player", "update(", "reset("],
    "coin.js": ["Game.Coin", "collected"],
    "enemy.js": ["Game.Enemy", "collideWithPlayer"],
    "level.js": ["Game.Level", "platforms", "getCollisions"],
    "game.js": ["requestAnimationFrame", "canvas", "new G.Level", "new G.Player"],
}
for fname, needles in sig_checks.items():
    with open(f"{base}/{fname}", "r", encoding="utf-8") as f:
        src = f.read()
    for n in needles:
        must(n in src, f"{fname} missing expected token: {n}")

# Optional syntax check with Node.js if available
node_ok = True
node_msgs = []
def node_check(js_path):
    try:
        r = subprocess.run(["node", "--check", js_path], capture_output=True, text=True)
        return r.returncode == 0, (r.stdout.strip() + "\n" + r.stderr.strip()).strip()
    except FileNotFoundError:
        return None, "node not found"

for fname in ["core.js","input.js","player.js","coin.js","enemy.js","level.js","game.js"]:
    ok, msg = node_check(f"{base}/{fname}")
    if ok is None:
        node_ok = None
        node_msgs.append("node not found; skipped syntax checks")
        break
    if not ok:
        node_ok = False
        node_msgs.append(f"{fname}: {msg}")

if node_ok is False:
    raise AssertionError("Node.js syntax check failed: " + " | ".join(node_msgs))

summary = {
    "path": base,
    "files": list(files.keys()),
    "verified": True,
    "node": ("ok" if node_ok else "skipped" if node_ok is None else "failed"),
}
done(json.dumps(summary))
